const AffiliateAPI={EDGE_URL: `${window.__ENV__?.SUPABASE_URL||'https://pzcgvfhppglzfjavxuid.supabase.co'}/functions/v1`,async calculateCommission(sales,options={}){try{const response=await fetch(`${this.EDGE_URL}/calculate-commission`,{method: 'POST',headers:{'Content-Type': 'application/json','Authorization': `Bearer ${window.__ENV__?.SUPABASE_ANON_KEY||''}`},body: JSON.stringify({sales,tier: options.tier,isNewClient: options.isNewClient||false,isRepeatClient: options.isRepeatClient||false})});if(!response.ok){throw new Error(`API error: ${response.status}`);}return await response.json();}catch(error){return this.fallbackCalculation(sales,options);}},fallbackCalculation(sales,options={}){const tiers={bronze:{rate: 0.05,min: 0,label: 'Bronze'},silver:{rate: 0.08,min: 10000000,label: 'Silver'},gold:{rate: 0.12,min: 50000000,label: 'Gold'},platinum:{rate: 0.15,min: 100000000,label: 'Platinum'},diamond:{rate: 0.20,min: 500000000,label: 'Diamond'}};let tier='bronze';if(sales>=500000000)tier='diamond';else if(sales>=100000000)tier='platinum';else if(sales>=50000000)tier='gold';else if(sales>=10000000)tier='silver';const tierConfig=tiers[tier];const baseRate=tierConfig.rate;const baseCommission=Math.round(sales*baseRate);let bonusMultiplier=1;const bonusApplied=[];if(options.isNewClient){bonusMultiplier+=0.5;bonusApplied.push('New Client+50%');}if(options.isRepeatClient&&!options.isNewClient){bonusMultiplier+=0.2;bonusApplied.push('Repeat Client+20%');}if(sales>=50000000){bonusMultiplier+=0.1;bonusApplied.push('Bulk Order+10%');}const finalCommission=Math.round(baseCommission*bonusMultiplier);const finalRate=baseRate*bonusMultiplier;return{commission: finalCommission,rate: finalRate,tier,tierLabel: tierConfig.label,bonusApplied,breakdown:{baseSales: sales,baseRate: baseRate,baseCommission: baseCommission,bonusMultiplier: bonusMultiplier,finalCommission: finalCommission},_fallback: true};},formatCurrency(amount){return new Intl.NumberFormat('vi-VN',{style: 'currency',currency: 'VND'}).format(amount);},formatPercent(rate){return `${(rate*100).toFixed(1)}%`;}};window.AffiliateAPI=AffiliateAPI;